vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    float phi = (1+sqrt(5))/2;

    vec2 uv1;
    vec3 ret1;

    float xm = q3, ym = q4;
    vec2 zm = vec2(xm,ym);

    uv1 = abs(zm-abs(abs(vUv*2-1)*2-1));

    ret1 = texture(sampler_main,uv1).xyz;
    ret = texture(sampler_main,vUv).xyz;

    float fv = 0.5;
    ret = max((1-ret*2)*fv,ret1*(1-fv));

    ret *= 2.00;
    ret *= pow(hue_shader,phi);

  fragColor = ret;
}
